1	"""
2	POLARIS Research Observatory Dashboard Generator.
3	
4	Reads a JSONL trace file produced by PipelineTracer and generates
5	a self-contained HTML file with a modern three-panel layout inspired by
6	Consensus.app, Perplexity, and ChatGPT Deep Research.
7	
8	Layout:
9	  LEFT:   Pipeline navigator sidebar (220px fixed)
10	  CENTER: Report & analysis (scrollable, all sections visible)
11	  RIGHT:  Evidence panel (320px fixed, independently scrollable)
12	
13	All CSS and JS are inline. Only external dependency: Google Fonts (Inter).
14	
15	CLI: python scripts/generate_dashboard.py \
16	       --trace logs/pg_trace_V001.jsonl \
17	       --output outputs/dashboard_V001.html
18	"""
19	
20	import argparse
21	import html
22	import json
23	import math
24	import os
25	import sys
26	from collections import defaultdict
27	from pathlib import Path
28	
29	
30	# ---------------------------------------------------------------------------
31	# Data loading helpers
32	# ---------------------------------------------------------------------------
33	
34	def _load_events(trace_path: str) -> list[dict]:
35	    """Load all JSONL events from trace file."""
36	    events = []
37	    with open(trace_path, "r", encoding="utf-8") as f:
38	        for line_num, line in enumerate(f, 1):
39	            line = line.strip()
40	            if not line:
41	                continue
42	            try:
43	                events.append(json.loads(line))
44	            except json.JSONDecodeError as exc:
45	                print(f"  WARN: Skipping malformed line {line_num}: {exc}")
46	    return events
47	
48	
49	def _group_by_type(events: list[dict]) -> dict[str, list[dict]]:
50	    """Group events by their 'type' field."""
51	    grouped: dict[str, list[dict]] = defaultdict(list)
52	    for ev in events:
53	        grouped[ev.get("type", "unknown")].append(ev)
54	    return grouped
55	
56	
57	def _esc(text) -> str:
58	    """HTML-escape text for safe embedding."""
59	    return html.escape(str(text)) if text else ""
60	
61	
62	def _format_duration(ms: float) -> str:
63	    """Format milliseconds as human-readable duration."""
64	    if ms < 1000:
65	        return f"{ms:.0f}ms"
66	    if ms < 60000:
67	        return f"{ms / 1000:.1f}s"
68	    minutes = ms / 60000
69	    if minutes < 60:
70	        return f"{minutes:.1f}min"
71	    hours = minutes / 60
72	    return f"{hours:.1f}h"
73	
74	
75	def _format_cost(cost: float) -> str:
76	    """Format cost as USD string."""
77	    if cost < 0.01:
78	        return f"${cost:.4f}"
79	    return f"${cost:.2f}"
80	
81	
82	def _truncate(text: str, limit: int = 200) -> str:
83	    """Truncate text with ellipsis."""
84	    if not text:
85	        return ""
86	    if len(text) <= limit:
87	        return text
88	    return text[:limit] + "..."
89	
90	
91	def _extract_domain(url: str) -> str:
92	    """Extract domain from URL for display."""
93	    try:
94	        from urllib.parse import urlparse
95	        parsed = urlparse(url)
96	        domain = parsed.netloc
97	        if domain.startswith("www."):
98	            domain = domain[4:]
99	        return domain or url[:40]
100	    except Exception:
101	        return url[:40] if url else "unknown"
102	
