104	# ---------------------------------------------------------------------------
105	# Key metrics extraction
106	# ---------------------------------------------------------------------------
107	
108	def _extract_key_metrics(grouped: dict) -> dict:
109	    """Extract key pipeline metrics from grouped events.
110	
111	    Returns a dict with: faithfulness, final_evidence, total_words,
112	    total_citations, unique_sources, gate_passed, cost, total_duration,
113	    gold, silver, bronze, query, vector_id, iterations.
114	    """
115	    # --- Pipeline start metadata ---
116	    pipeline_starts = grouped.get("pipeline_start", [])
117	    query = ""
118	    vector_id = "unknown"
119	    if pipeline_starts:
120	        ps = pipeline_starts[0]
121	        query = ps.get("query", "")
122	        vector_id = ps.get("vector_id", ps.get("vid", "unknown"))
123	
124	    # --- Quality gate metrics ---
125	    gate_events = grouped.get("quality_gate", [])
126	    final_gate = None
127	    for g in reversed(gate_events):
128	        if g.get("gate") in ("post_synthesis_final", "post_synthesis"):
129	            final_gate = g
130	            break
131	
132	    total_words = final_gate.get("total_words", 0) if final_gate else 0
133	    total_citations = final_gate.get("total_citations", 0) if final_gate else 0
134	    unique_sources = final_gate.get("unique_sources", 0) if final_gate else 0
135	    gate_passed = final_gate.get("passed", False) if final_gate else False
136	
137	    # --- Faithfulness from iteration_decision ---
138	    faithfulness = 0.0
139	    iter_decisions = grouped.get("iteration_decision", [])
140	    faith_history = []
141	    for d in iter_decisions:
142	        rationale = d.get("rationale", {})
143	        fs = rationale.get("faithfulness_score", 0)
144	        if fs > 0:
145	            faith_history.append(fs)
146	    if faith_history:
147	        faithfulness = faith_history[-1]
148	
149	    # --- Evidence counts and tiers ---
150	    evidence_events = grouped.get("evidence", [])
151	    final_evidence = 0
152	    gold = 0
153	    silver = 0
154	    bronze = 0
155	    for e in evidence_events:
156	        action = e.get("action", "")
157	        if action in ("report_assembled", "accumulated", "verified",
158	                       "extracted", "relevance_scored"):
159	            final_evidence = max(final_evidence, e.get("count", 0))
160	        if action == "extracted":
161	            gold = max(gold, e.get("gold", 0))
162	            silver = max(silver, e.get("silver", 0))
163	            bronze = max(bronze, e.get("bronze", 0))
164	
165	    # --- Duration ---
166	    node_ends = grouped.get("node_end", [])
167	    total_duration = sum(e.get("duration_ms", 0) for e in node_ends)
168	
169	    # --- Cost ---
170	    llm_calls = grouped.get("llm_call", [])
171	    reasoning_evts = grouped.get("reasoning_capture", [])
172	
173	    # Try cumulative_cost from llm_calls first
174	    cumulative_costs = [c.get("cumulative_cost_usd", 0) for c in llm_calls if c.get("cumulative_cost_usd", 0) > 0]
175	    if cumulative_costs:
176	        cost = max(cumulative_costs)
177	    else:
178	        # Fallback: estimate from tokens
179	        tok_in = max(
180	            sum(e.get("input_tokens", 0) for e in reasoning_evts),
181	            sum(e.get("input_tokens", 0) for e in llm_calls),
182	        )
183	        tok_out = max(
184	            sum(e.get("output_tokens", 0) for e in reasoning_evts),
185	            sum(e.get("output_tokens", 0) for e in llm_calls),
186	        )
187	        cost = (tok_in * 1.50 + tok_out * 6.00) / 1_000_000
188	
189	    # --- Iterations ---
190	    iterations = len(iter_decisions)
191	
192	    # --- LLM stats ---
193	    total_tokens_in = sum(c.get("input_tokens", 0) for c in llm_calls)
194	    total_tokens_out = sum(c.get("output_tokens", 0) for c in llm_calls)
195	
196	    return {
197	        "faithfulness": faithfulness,
198	        "faith_history": faith_history,
199	        "final_evidence": final_evidence,
200	        "total_words": total_words,
201	        "total_citations": total_citations,
202	        "unique_sources": unique_sources,
203	        "gate_passed": gate_passed,
204	        "cost": cost,
205	        "total_duration": total_duration,
206	        "gold": gold,
207	        "silver": silver,
208	        "bronze": bronze,
209	        "query": query,
210	        "vector_id": vector_id,
211	        "iterations": iterations,
212	        "llm_calls": len(llm_calls),
213	        "total_tokens_in": total_tokens_in,
214	        "total_tokens_out": total_tokens_out,
215	    }
